"""
install_scheduler_phase1234.py
Run from C:\\vantro:    python install_scheduler_phase1234.py

Phase 1-4 of the Scheduler build:
  - 6 API routes (schedule overview, team schedules, admin time off list/create,
    admin time off approve/reject, installer time off list/create, installer balance)
  - Updated /api/admin/settings to accept sick_auto_approve
  - 1 new admin page: /admin/schedule (sticky tabs)
  - 4 tab components (Overview, Defaults, Team, Time off)
  - Slimmed SettingsTab (schedule moved to /admin/schedule)

After running this:
  1. Run migration_3_sick_auto_approve.sql in Vantro Supabase
  2. python patch_admin_dashboard.py  (adds Scheduler sidebar item)
  3. npm run build
  4. git add / commit / push
"""
import base64, os, sys

FILES = {
  "app/admin/schedule/page.tsx": "",
  "app/api/admin/schedule-overview/route.ts": "",
  "app/api/admin/settings/route.ts": "",
  "app/api/admin/team-schedules/route.ts": "",
  "app/api/admin/time-off/[id]/route.ts": "",
  "app/api/admin/time-off/route.ts": "",
  "app/api/installer/time-off/balance/route.ts": "",
  "app/api/installer/time-off/route.ts": "",
  "components/admin/SettingsTab.tsx": "",
  "components/admin/schedule/DefaultsTab.tsx": "",
  "components/admin/schedule/OverviewTab.tsx": "",
  "components/admin/schedule/TeamTab.tsx": "",
  "components/admin/schedule/TimeOffTab.tsx": ""
}

def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro"):
        print(f"WARNING: cwd is {cwd}")
        print("This script should be run from C:\\vantro. Continue anyway? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    for rel_path, b64 in FILES.items():
        full_path = os.path.join(cwd, rel_path.replace("/", os.sep))
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        contents = base64.b64decode(b64).decode("utf-8")
        with open(full_path, "w", encoding="utf-8", newline="\n") as f:
            f.write(contents)
        print(f"  wrote: {rel_path}  ({len(contents)} bytes)")

    print()
    print(f"All {len(FILES)} files written.")
    print()
    print("Next:")
    print("  1. Run migration_3_sick_auto_approve.sql in Vantro Supabase")
    print("  2. python patch_admin_dashboard.py  (adds Scheduler sidebar item)")
    print("  3. npm run build")
    print("  4. git add / commit / push")

if __name__ == "__main__":
    main()
